getRouter(): express.Router {
  const router = Router();

  router.get('/.backstage/scheduler/v1/tasks', async (_, res) => {
    const globalState = await TaskWorker.taskStates(
      await this.databaseFactory(),
    );

    const tasks = new Array<TaskApiTasksResponse>();
    for (const task of this.allScheduledTasks) {
      tasks.push({
        taskId: task.id,
        pluginId: this.pluginId,
        scope: task.scope,
        settings: task.settings,
        taskState:
          this.localWorkersById.get(task.id)?.taskState() ??
          globalState.get(task.id) ??
          null,
        workerState:
          this.localWorkersById.get(task.id)?.workerState() ??
          this.globalWorkersById.get(task.id)?.workerState() ??
          null,
      });
    }

    res.json({ tasks });
  });

  router.post(
    '/.backstage/scheduler/v1/tasks/:id/trigger',
    async (req, res) => {
      const { id } = req.params;
      await this.triggerTask(id);
      res.status(200).end();
    },
  );

  router.post(
    '/.backstage/scheduler/v1/tasks/:id/cancel',
    async (req, res) => {
      const { id } = req.params;
      await this.cancelTask(id);
      res.status(200).end();
    },
  );

  return router;
}

function favicon (path, options) {
  var opts = options || {}

  var icon // favicon cache
  var maxAge = calcMaxAge(opts.maxAge)

  if (!path) {
    throw new TypeError('path to favicon.ico is required')
  }

  if (Buffer.isBuffer(path)) {
    icon = createIcon(Buffer.from(path), maxAge)
  } else if (typeof path === 'string') {
    path = resolveSync(path)
  } else {
    throw new TypeError('path to favicon.ico must be string or buffer')
  }

  return function favicon (req, res, next) {
    if (getPathname(req) !== '/favicon.ico') {
      next()
      return
    }

    if (req.method !== 'GET' && req.method !== 'HEAD') {
      res.statusCode = req.method === 'OPTIONS' ? 200 : 405
      res.setHeader('Allow', 'GET, HEAD, OPTIONS')
      res.setHeader('Content-Length', '0')
      res.end()
      return
    }

    if (icon) {
      send(req, res, icon)
      return
    }

    fs.readFile(path, function (err, buf) {
      if (err) return next(err)
      icon = createIcon(buf, maxAge)
      send(req, res, icon)
    })
  }
}

function middlewareWrapper(o) {
  // if options are static (either via defaults or custom options passed in), wrap in a function
  var optionsCallback = null;
  if (typeof o === 'function') {
    optionsCallback = o;
  } else {
    optionsCallback = function (req, cb) {
      cb(null, o);
    };
  }

  return function corsMiddleware(req, res, next) {
    optionsCallback(req, function (err, options) {
      if (err) {
        next(err);
      } else {
        var corsOptions = assign({}, defaults, options);
        var originCallback = null;
        if (corsOptions.origin && typeof corsOptions.origin === 'function') {
          originCallback = corsOptions.origin;
        } else if (corsOptions.origin) {
          originCallback = function (origin, cb) {
            cb(null, corsOptions.origin);
          };
        }

        if (originCallback) {
          originCallback(req.headers.origin, function (err2, origin) {
            if (err2 || !origin) {
              next(err2);
            } else {
              corsOptions.origin = origin;
              cors(corsOptions, req, res, next);
            }
          });
        } else {
          next();
        }
      }
    });
  };
}

function send (req, res, status, headers, message) {
  function write () {
    // response body
    var body = createHtmlDocument(message)

    // response status
    res.statusCode = status

    if (req.httpVersionMajor < 2) {
      res.statusMessage = statuses.message[status]
    }

    // remove any content headers
    res.removeHeader('Content-Encoding')
    res.removeHeader('Content-Language')
    res.removeHeader('Content-Range')

    // response headers
    for (const [key, value] of Object.entries(headers ?? {})) {
      res.setHeader(key, value)
    }

    // security headers
    res.setHeader('Content-Security-Policy', "default-src 'none'")
    res.setHeader('X-Content-Type-Options', 'nosniff')

    // standard headers
    res.setHeader('Content-Type', 'text/html; charset=utf-8')
    res.setHeader('Content-Length', Buffer.byteLength(body, 'utf8'))

    if (req.method === 'HEAD') {
      res.end()
      return
    }

    res.end(body, 'utf8')
  }

  if (isFinished(req)) {
    write()
    return
  }

  // unpipe everything from the request
  req.unpipe()

  // flush the request
  onFinished(req, write)
  req.resume()
}

mapLayers(layers: PlatformLayer[]) {
  const rawApp: any = this.app.getApp();
  const version = getVersion();

  for (const layer of layers) {
    const handlers = layer.getArgs(false);
    const {path, wildcard} = convertPath(layer.path, version as "v4" | "v5");

    layer.path = path;

    if (layer.method === "statics") {
      rawApp.use(path, this.statics(path, layer.opts as any));
      continue;
    }

    if (wildcard) {
      handlers.unshift(((req: Express.Request, _: any, next: Express.NextFunction) => {
        if (req.params["0"] && !req.params[wildcard]) {
          req.params[wildcard] = req.params["0"];
        }

        if (isArray(req.params[wildcard])) {
          req.params[wildcard] = req.params[wildcard].join("/");
        }

        if (wildcard === "wildcard") {
          req.params["*"] ||= req.params[wildcard];
        }

        next();
      }) as any);
    }

    rawApp[layer.method](path, ...handlers);
  }
}

private handleFormExplode(
  req: Request,
  name: string,
  schema: SchemaObject,
  parameter: ParameterObject,
): void {
  // fetch the keys used for this kind of explode
  const type = schema.type;
  const hasXOf = schema['allOf'] || schema['oneOf'] || schema['anyOf'];
  const properties = hasXOf
    ? xOfProperties(schema)
    : type === 'object'
      ? Object.keys(schema.properties ?? {})
      : [];

  this.explodedJsonObjectAndMutateRequest(
    req,
    parameter.in,
    name,
    properties,
    schema,
  );

  function xOfProperties(schema: Schema): string[] {
    return ['allOf', 'oneOf', 'anyOf'].reduce((acc, key) => {
      if (!schema.hasOwnProperty(key)) {
        return acc;
      } else {
        const foundProperties = schema[key].reduce((acc2, obj) => {
          return obj.type === 'object'
            ? acc2.concat(...Object.keys(obj.properties))
            : acc2;
        }, []);
        return foundProperties.length > 0
          ? acc.concat(...foundProperties)
          : acc;
      }
    }, []);
  }
}

private extractResponseSchemaNodes(
  node: Root<OpenAPIV3.OperationObject>,
): Root<SchemaObject>[] {
  const op = node.schema;
  const responses = op.responses;

  if (!responses) return [];

  const schemas: Root<SchemaObject>[] = [];
  for (const [statusCode, response] of Object.entries(responses)) {
    const rschema = this.resolveSchema<OpenAPIV3.ResponseObject>(response);
    if (!rschema) {
      // issue #553
      // TODO the schema failed to resolve.
      // This can occur with multi-file specs
      // improve resolution, so that rschema resolves (use json ref parser?)
      continue;
    }
    responses[statusCode] = rschema;

    if (rschema.content) {
      for (const [type, mediaType] of Object.entries(rschema.content)) {
        const schema = this.resolveSchema<SchemaObject>(mediaType?.schema);
        if (schema) {
          rschema.content[type].schema = schema;
          const path = [
            ...node.path,
            'responses',
            statusCode,
            'content',
            type,
            'schema',
          ];

          // TODO replace with visitor
          this.removeExamples(rschema.content[type]);

          schemas.push(new Root(schema, path));
        }
      }
    }
  }
  return schemas;
}

async function transform(root: SgRoot<Js>): Promise<string | null> {
  const rootNode = root.root()

  const nodes = rootNode.findAll({
    rule: {
      pattern: '$OBJ.$METHOD($ARG)',
    },
    constraints: {
      METHOD: { regex: '^(redirect|location)$' },
      ARG: { pattern: { context: "'back'", strictness: 'relaxed' } },
    },
  })

  const edits: Edit[] = []

  for (const call of nodes) {
    const arg = call.getMatch('ARG')
    const obj = call.getMatch('OBJ')
    if (!arg || !obj) continue

    if (getStringLiteralValue(arg) !== 'back') continue

    const objDef = obj.definition({ resolveExternal: false })
    if (!objDef) continue

    const isParameter = objDef.node.matches({
      rule: { inside: { kind: 'formal_parameters', stopBy: 'end' } },
    })
    if (!isParameter) continue

    const parameters = findParentFunctionParameters(objDef.node)
    if (!parameters) continue

    const firstParameter = parameters.find({ rule: { kind: 'identifier' } })
    if (!firstParameter) continue

    const requestName = firstParameter.text()

    edits.push(arg.replace(`${requestName}.get("Referrer") || "/"`))
  }

  if (edits.length === 0) return null
  return rootNode.commitEdits(edits)
}

async function transform(root: SgRoot<Js>): Promise<string | null> {
  const rootNode = root.root()

  const nodes = rootNode.findAll({
    rule: {
      pattern: '$OBJ.$METHOD($$$ARG)',
    },
    constraints: {
      METHOD: { regex: '^(del)$' },
    },
  })

  if (!nodes.length) return null

  const edits: Edit[] = []

  for (const call of nodes) {
    const method = call.getMatch('METHOD')
    const args = call.getMultipleMatches('ARG')
    if (!method) continue

    // $$$ARG yields argument nodes interleaved with separators, so arg nodes are at 0,2,4...
    const first = args[0]
    if (!first) continue

    const isString = first.is('string')
    const isRegexp = first.is('regexp') || first.is('regex') || first.is('regular_expression')
    const isArray = first.is('array') || first.is('array_expression')

    if (!isString && !isRegexp && !isArray) continue

    edits.push(method.replace('delete'))
  }

  if (!edits.length) return null

  return rootNode.commitEdits(edits)
}

function fastparse (str) {
  if (typeof str !== 'string' || str.charCodeAt(0) !== 0x2f /* / */) {
    return parse(str)
  }

  var pathname = str
  var query = null
  var search = null

  // This takes the regexp from https://github.com/joyent/node/pull/7878
  // Which is /^(\/[^?#\s]*)(\?[^#\s]*)?$/
  // And unrolls it into a for loop
  for (var i = 1; i < str.length; i++) {
    switch (str.charCodeAt(i)) {
      case 0x3f: /* ?  */
        if (search === null) {
          pathname = str.substring(0, i)
          query = str.substring(i + 1)
          search = str.substring(i)
        }
        break
      case 0x09: /* \t */
      case 0x0a: /* \n */
      case 0x0c: /* \f */
      case 0x0d: /* \r */
      case 0x20: /*    */
      case 0x23: /* #  */
      case 0xa0:
      case 0xfeff:
        return parse(str)
    }
  }

  var url = Url !== undefined
    ? new Url()
    : {}

  url.path = str
  url.href = str
  url.pathname = pathname

  if (search !== null) {
    url.query = query
    url.search = search
  }

  return url
}
